(window.webpackJsonp=window.webpackJsonp||[]).push([[474],{498:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">A</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">B</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxUncrossedLines = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">A, B</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> aL=A.length,bL=B.length;\\n  <span class=\\"hljs-keyword\\">let</span> arr=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;=aL;i++){\\n    arr[i]=[]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;=bL;j++)arr[i][j]=<span class=\\"hljs-number\\">0</span>\\n  }\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;=aL;i++){\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">1</span>;j&lt;=bL;j++){\\n      <span class=\\"hljs-keyword\\">if</span>(A[i<span class=\\"hljs-number\\">-1</span>]===B[j<span class=\\"hljs-number\\">-1</span>]) arr[i][j]=arr[i<span class=\\"hljs-number\\">-1</span>][j<span class=\\"hljs-number\\">-1</span>]+<span class=\\"hljs-number\\">1</span>\\n      <span class=\\"hljs-keyword\\">else</span> arr[i][j]=<span class=\\"hljs-built_in\\">Math</span>.max(arr[i<span class=\\"hljs-number\\">-1</span>][j],arr[i][j<span class=\\"hljs-number\\">-1</span>])\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> arr[aL][bL]\\n};\\n</code></pre>\\n"],"titleSlug":"uncrossed-lines","hasThinking":false,"content":"<p>\u5728\u4e24\u6761\u72ec\u7acb\u7684\u6c34\u5e73\u7ebf\u4e0a\u6309\u7ed9\u5b9a\u7684\u987a\u5e8f\u5199\u4e0b <code>nums1</code> \u548c <code>nums2</code> \u4e2d\u7684\u6574\u6570\u3002</p>\\n\\n<p>\u73b0\u5728\uff0c\u53ef\u4ee5\u7ed8\u5236\u4e00\u4e9b\u8fde\u63a5\u4e24\u4e2a\u6570\u5b57 <code>nums1[i]</code>\xa0\u548c <code>nums2[j]</code>\xa0\u7684\u76f4\u7ebf\uff0c\u8fd9\u4e9b\u76f4\u7ebf\u9700\u8981\u540c\u65f6\u6ee1\u8db3\u6ee1\u8db3\uff1a</p>\\n\\n<ul>\\n\\t<li>\xa0<code>nums1[i] == nums2[j]</code></li>\\n\\t<li>\u4e14\u7ed8\u5236\u7684\u76f4\u7ebf\u4e0d\u4e0e\u4efb\u4f55\u5176\u4ed6\u8fde\u7ebf\uff08\u975e\u6c34\u5e73\u7ebf\uff09\u76f8\u4ea4\u3002</li>\\n</ul>\\n\\n<p>\u8bf7\u6ce8\u610f\uff0c\u8fde\u7ebf\u5373\u4f7f\u5728\u7aef\u70b9\u4e5f\u4e0d\u80fd\u76f8\u4ea4\uff1a\u6bcf\u4e2a\u6570\u5b57\u53ea\u80fd\u5c5e\u4e8e\u4e00\u6761\u8fde\u7ebf\u3002</p>\\n\\n<p>\u4ee5\u8fd9\u79cd\u65b9\u6cd5\u7ed8\u5236\u7ebf\u6761\uff0c\u5e76\u8fd4\u56de\u53ef\u4ee5\u7ed8\u5236\u7684\u6700\u5927\u8fde\u7ebf\u6570\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/04/28/142.png\\" style=\\"height: 72px; width: 100px;\\" /></strong>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums1 = <span id=\\"example-input-1-1\\">[1,4,2]</span>, nums2 = <span id=\\"example-input-1-2\\">[1,2,4]</span>\\n<strong>\u8f93\u51fa\uff1a</strong><span id=\\"example-output-1\\">2</span>\\n<strong>\u89e3\u91ca\uff1a</strong>\u53ef\u4ee5\u753b\u51fa\u4e24\u6761\u4e0d\u4ea4\u53c9\u7684\u7ebf\uff0c\u5982\u4e0a\u56fe\u6240\u793a\u3002 \\n\u4f46\u65e0\u6cd5\u753b\u51fa\u7b2c\u4e09\u6761\u4e0d\u76f8\u4ea4\u7684\u76f4\u7ebf\uff0c\u56e0\u4e3a\u4ece nums1[1]=4 \u5230 nums2[2]=4 \u7684\u76f4\u7ebf\u5c06\u4e0e\u4ece nums1[2]=2 \u5230 nums2[1]=2 \u7684\u76f4\u7ebf\u76f8\u4ea4\u3002\\n</pre>\\n\\n<div>\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums1 = <span id=\\"example-input-2-1\\">[2,5,1,2,5]</span>, nums2 = <span id=\\"example-input-2-2\\">[10,5,2,1,5,2]</span>\\n<strong>\u8f93\u51fa\uff1a</strong><span id=\\"example-output-2\\">3</span>\\n</pre>\\n\\n<div>\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums1 = <span id=\\"example-input-3-1\\">[1,3,7,1,7,5]</span>, nums2 = <span id=\\"example-input-3-2\\">[1,9,2,5,1]</span>\\n<strong>\u8f93\u51fa\uff1a</strong><span id=\\"example-output-3\\">2</span></pre>\\n\\n<p>\xa0</p>\\n</div>\\n</div>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= nums1.length <= 500</code></li>\\n\\t<li><code>1 <= nums2.length <= 500</code></li>\\n\\t<li><code><font face=\\"monospace\\">1 <= nums1[i], nums2[i] <= 2000</font></code></li>\\n</ul>\\n\\n<p>\xa0</p>\\n","title":"1035. \u4e0d\u76f8\u4ea4\u7684\u7ebf","relatedTags":["\u6570\u7ec4"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1035"}')}}]);